class NotificationRegistry {
    private static final Map<NotificationType, Supplier<Notification>>
        registry = new EnumMap<>(NotificationType.class);

    static {
        registry.put(EMAIL,    EmailNotification::new);
        registry.put(SMS,      SMSNotification::new);
        registry.put(PUSH,     PushNotification::new);
        registry.put(WHATSAPP, WhatsAppNotification::new);
    }

    static Notification create(NotificationType type) {
        Supplier<Notification> supplier = registry.get(type);
        if (supplier == null) throw new IllegalArgumentException("Unknown: " + type);
        return supplier.get(); // Supplier.get() = lazy creation
    }
}

