abstract class NotificationService {
    // ===== THE FACTORY METHOD =====
    // Subclasses override this to provide their specific product.
    protected abstract Notification createNotification();

    // Template: shared orchestration written ONCE.
    // validate -> create -> send -> log -> audit
    public final void sendNotification(String message) {
        validate(message);
        Notification n = createNotification(); // HOOK: subclass decides
        n.send(message);
        log(n.getChannel(), message);
        audit(n.getChannel());
    }
    // validate(), log(), audit() -- written ONCE, not duplicated
}

