@Configuration
class NotificationConfig {
    @Bean("email") // THIS is a factory method!
    Notification email() {
        return new EmailNotification(loadSmtpConfig());
    }

    @Bean("sms")
    Notification sms() {
        return new SMSNotification(loadApiKey());
    }
}

// Client: @Autowired IS the factory call
